const CHEER_FACES=["happy","big_smile","laughing","wink","playful","tongue_out","star_eyes","love","cool","blush","smirk","laugh_tears"];
function rollBeeFace(){return CHEER_FACES[Math.floor(Math.random()*CHEER_FACES.length)];}
function rollBeeBody(){let r=Math.random();for(const[c,p]of BODY_ODDS){if(r<p)return c;r-=p;}return"yellow";}
const FACE_POS={tongue_out:"width:44%;top:23%",money_eyes:"width:50%;top:22%",crying:"width:52%;top:22%",pleading:"width:54%",surprised:"width:54%"};
function beeSprite(spec,h,cls){
 spec=(typeof spec==="string")?{body:spec}:(spec||{});
 const src=BEE_BODIES[spec.body]||BEE_BODIES.yellow;
 let layers=`<img class="bb-body" src="${src}" alt="">`;
 if(spec.face&&BEE_FACES[spec.face])layers+=`<img class="bb-face" src="${BEE_FACES[spec.face]}" alt=""${FACE_POS[spec.face]?` style="${FACE_POS[spec.face]}"`:""}>`;
 const accs=Array.isArray(spec.acc)?spec.acc:(spec.acc?[spec.acc]:[]);
 for(const ac of accs){if(BEE_ACCS[ac])layers+=`<img class="bb-acc" src="${BEE_ACCS[ac]}" style="${ACC_POS[ac]||"top:0;width:40%"}" alt="">`;}
 return `<span class="beespr ${cls||""}" style="width:${h}px;height:${h}px">${layers}</span>`;
}
const MOJI={idle:"data:image/png;base64,",wave:"data:image/png;base64,",happy:"data:image/png;base64,",thumbs:"data:image/png;base64,",collect:"data:image/png;base64,",build:"data:image/png;base64,",event:"data:image/png;base64,",win:"data:image/png;base64,"};
function mojiCheer(pose,ms){
 const d=document.createElement("div");
 d.style.cssText="position:fixed;right:8px;bottom:120px;z-index:400;pointer-events:none";
 d.className="mojipop";d.innerHTML=mojiImg(pose,110);
 document.body.appendChild(d);
 setTimeout(()=>{d.style.transition="opacity .4s,transform .4s";d.style.opacity="0";d.style.transform="translateY(24px)";setTimeout(()=>d.remove(),450);},ms||1600);
}
function mojiImg(pose,h,cls){return `<img src="${MOJI[pose]||MOJI.idle}" class="moji ${cls||""}" style="height:${h}px;width:auto" alt="Moji">`;}
const IMG_PACKS=["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"];
/* BeeMoji! v2 — bright custom-art build. All art = inline SVG placeholders matching Bee King's BeeMoji style; swap symbol contents for final assets. */

const I=(id,s=24)=>`<svg class="ic" width="${s}" height="${s}" viewBox="0 0 100 100"><use href="#${id}"/></svg>`;
/* Queens = base body + face + crown (one royal shape, many styles) */
const QUEEN_LOOKS={
 q_zombee:{body:"green",face:"dizzy",acc:"crown_silver"},
 q_disco:{body:"purple",face:"playful",acc:["crown_rose","headphones"]},
 q_sleepy:{body:"blue",face:"sleeping",acc:["crown_silver","zzz"]},
 q_star:{body:"yellow",face:"star_eyes",acc:"crown_diamond"},
 q_love:{body:"pink",face:"love",acc:"crown_rose"},
 q_money:{body:"green",face:"money_eyes",acc:"crown_gold"},
 q_coffee:{body:"orange",face:"love",acc:["crown_gold","coffee_cup"]},
 q_angel:{body:"yellow",face:"halo",acc:"crown_diamond"},
 q_cool:{body:"blue",face:"cool",acc:"crown_silver"},
 q_stache:{body:"orange",face:"smirk",acc:"crown_gold"},
 q_cowboy:{body:"yellow",face:"wink",acc:"crown_gold"},
};
const WORKER_LOOKS={
 w_forager:{body:"yellow",face:"happy"},
 w_nurse:{body:"pink",face:"happy",acc:["nurse_cap","eyelashes"]},
 w_guard:{body:"orange",face:"grimace"},
 w_scout:{body:"green",face:"wide_eyes"},
 w_under:{body:"purple",face:"neutral"},
 w_builder:{body:"blue",face:"sweat_smile"},
 w_drone:{body:"yellow",face:"eye_roll"},
};
function artHTML(id,s=24){const lk=QUEEN_LOOKS[id]||WORKER_LOOKS[id];return lk?beeSprite(lk,s):I(artOf(id),s);}
const ICON_LOOKS={
 a_s_kingbee:{body:"yellow",face:"big_smile",acc:"crown"},
 a_s_grumble:{body:"purple",face:"grimace",acc:"bandit_mask"},
 a_beefly:{body:"yellow",face:"happy"},
};
function iconHTML(ic,s=24){
 if(ic&&ic.startsWith("bee:")){const p=ic.split(":");return beeSprite({body:p[1],face:p[2],acc:p[3]||undefined},s);}
 if(ICON_LOOKS[ic])return beeSprite(ICON_LOOKS[ic],s);
 if(ic&&ic.startsWith("a_q_")&&QUEEN_LOOKS["q_"+ic.slice(4)])return beeSprite(QUEEN_LOOKS["q_"+ic.slice(4)],s);
 if(ic&&ic.startsWith("a_w_")&&WORKER_LOOKS["w_"+ic.slice(4)])return beeSprite(WORKER_LOOKS["w_"+ic.slice(4)],s);
 return I(ic,s);
}